BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?name ?value ?unit WHERE {
  ?elem rdf:type vocab:tmt%20requirement ;
        vocab:NamedElement_name ?name .
  FILTER(
    (
      CONTAINS(LCASE(STR(?name)), LCASE("misalignment")) &&
      CONTAINS(LCASE(STR(?name)), LCASE("M1"))
    ) ||
    (
      CONTAINS(LCASE(STR(?name)), LCASE("sensor offset")) &&
      CONTAINS(LCASE(STR(?name)), LCASE("M1"))
    )
  )
  OPTIONAL {
    ?elem vocab:Element_ownedElement+ ?param .
    ?param rdf:type vocab:property .
    OPTIONAL { ?param vocab:NamedElement_name ?pname . }
    OPTIONAL { ?param vocab:Property_defaultValue ?value . }
  }
  OPTIONAL {
    ?elem vocab:Element_ownedElement+ ?spec .
    ?spec vocab:ValueSpecification_expression ?expr .
    OPTIONAL { ?expr vocab:ElementValue_value ?value . }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?prop ?value ?pname WHERE {
  ?elem rdf:type vocab:tmt%20requirement .
  ?elem vocab:NamedElement_name ?name .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("M1")) &&
    (
      CONTAINS(LCASE(STR(?name)), LCASE("offset")) ||
      CONTAINS(LCASE(STR(?name)), LCASE("misalign")) ||
      CONTAINS(LCASE(STR(?name)), LCASE("Calibration")) ||
      CONTAINS(LCASE(STR(?name)), LCASE("Warping")) ||
      CONTAINS(LCASE(STR(?name)), LCASE("Actuator"))
    )
  )
  OPTIONAL { ?elem ?prop ?value . }
  OPTIONAL {
    ?elem vocab:Element_ownedElement+ ?child .
    ?child rdf:type ?childType .
    OPTIONAL { ?child vocab:NamedElement_name ?pname . }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqName ?propName ?num ?unit WHERE {
  ?req rdf:type vocab:tmt%20requirement ;
       vocab:NamedElement_name ?reqName .
  FILTER(
    (CONTAINS(LCASE(STR(?reqName)), LCASE("M1")) &&
     (CONTAINS(LCASE(STR(?reqName)), LCASE("misalign")) ||
      CONTAINS(LCASE(STR(?reqName)), LCASE("offset"))))
    )
  .
  OPTIONAL {
    ?req vocab:Element_ownedElement+ ?child .
    ?child rdf:type vocab:property .
    OPTIONAL { ?child vocab:NamedElement_name ?propName . }
    OPTIONAL { ?child vocab:Property_defaultValue ?numNode .
              ?numNode vocab:NamedElement_name ?num ;
                        vocab:NamedElement_qualifiedName ?unit .
    }
  }
  OPTIONAL {
    ?req vocab:Element_ownedElement+ ?child2 .
    ?child2 rdf:type vocab:property .
    OPTIONAL { ?child2 vocab:NamedElement_name ?propName . }
    OPTIONAL { ?child2 vocab:defaultValue ?val .
               ?val vocab:LiteralString_value ?num .
    }
  }
} 
LIMIT 25
